def binary_search(arr, target):
    left, right = 0, len(arr) - 1  # Initialize right to the last valid index

    while left <= right:
        mid = (left + right) // 2

        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1  # Target must be in the right half
        else:
            right = mid - 1 # Target must be in the left half

    return -1

